async (params, browser) => {
  // Search LinkedIn people
  await browser.open('https://www.linkedin.com/search/results/people/')

  // Wait for search results
  await browser.waitForSelector('.reusable-search__result-container, .search-results-container', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('.reusable-search__result-container, li.reusable-search__result-container'); for (let i = 0; i < Math.min(cards.length, 10); i++) { const card = cards[i]; const nameEl = card.querySelector('.entity-result__title-text a span[aria-hidden="true"], .entity-result__title-text a'); const headlineEl = card.querySelector('.entity-result__primary-subtitle'); const locationEl = card.querySelector('.entity-result__secondary-subtitle'); const linkEl = card.querySelector('.entity-result__title-text a, a.app-aware-link'); results.push({ name: nameEl ? nameEl.textContent.trim() : 'Unknown', headline: headlineEl ? headlineEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', profile_url: linkEl ? linkEl.href.split('?')[0] : '' }); } return { result_count: results.length, results: results }`)

  return search_results
}
